#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX_N 10
#define MAX_M 20

// Structure to represent a state
typedef struct {
    int boatman;
    int animals[MAX_N];
} State;

// Function to check if a state is valid
int isValid(State *state, int relations[MAX_M][2], int M) {
    // Check if any animal is eaten by another
    for (int i = 0; i < MAX_N; i++) {
        for (int j = 0; j < MAX_M; j++) {
            if (state->animals[i] == state->boatman && state->animals[relations[j][0] - 1] == state->boatman && relations[j][1] - 1 == i) {
                return 0;
            }
        }
    }
    return 1;
}

// Function to perform BFS
int bfs(int N, int M, int relations[MAX_M][2]) {
    // Create a queue to store states
    State *queue = (State *)malloc(sizeof(State) * (1 << N));
    int front = 0, rear = 0;
    State *currentState = (State *)malloc(sizeof(State));
    currentState->boatman = 0;
    for (int i = 0; i < N; i++) {
        currentState->animals[i] = 0;
    }
    queue[rear++] = *currentState;
    while (front < rear) {
        State *state = &queue[front++];
        // Check if the current state is the goal state
        if (state->boatman == 1 && state->animals[0] == 1 && state->animals[1] == 1 && state->animals[2] == 1) {
            free(queue);
            free(currentState);
            return 1;
        }
        // Generate all possible next states
        for (int i = 0; i < N; i++) {
            if (state->animals[i] == state->boatman) {
                State *nextState = (State *)malloc(sizeof(State));
                *nextState = *state;
                nextState->boatman = 1 - nextState->boatman;
                nextState->animals[i] = 1 - nextState->animals[i];
                if (isValid(nextState, relations, M)) {
                    queue[rear++] = *nextState;
                }
                free(nextState);
            }
        }
    }
    free(queue);
    free(currentState);
    return 0;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        int relations[MAX_M][2];
        for (int i = 0; i < M; i++) {
            scanf("%d %d", &relations[i][0], &relations[i][1]);
        }
        if (bfs(N, M, relations)) {
            printf("YES\n");
        } else {
            printf("NO\n");
        }
    }
    return 0;
}

