import java.util.LinkedList;
import java.util.Queue;
import java.util.Scanner;
public class Main {
    static final int MAX_N = 10;
    static final int MAX_M = 20;
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int N = scanner.nextInt();
            int M = scanner.nextInt();
            int[][] relations = new int[M][2];
            for (int i = 0; i < M; i++) {
                relations[i][0] = scanner.nextInt();
                relations[i][1] = scanner.nextInt();
            }
            System.out.println(bfs(N, M, relations) ? "YES" : "NO");
        }
    }
    public static boolean bfs(int N, int M, int[][] relations) {
        // Create a queue to store states
        Queue<State> queue = new LinkedList<>();
        State currentState = new State();
        currentState.boatman = 0;
        for (int i = 0; i < N; i++) {
            currentState.animals[i] = 0;
        }
        queue.add(currentState);
        while (!queue.isEmpty()) {
            State state = queue.poll();
            // Check if the current state is the goal state
            if (state.boatman == 1 && state.animals[0] == 1 && state.animals[1] == 1 && state.animals[2] == 1) {
                return true;
            }
            // Generate all possible next states
            for (int i = 0; i < N; i++) {
                if (state.animals[i] == state.boatman) {
                    State nextState = new State();
                    nextState.boatman = 1 - state.boatman;
                    System.arraycopy(state.animals, 0, nextState.animals, 0, N);
                    nextState.animals[i] = 1 - nextState.animals[i];
                    if (isValid(nextState, relations)) {
                        queue.add(nextState);
                    }
                }
            }
        }
        return false;
    }
    public static boolean isValid(State state, int[][] relations) {
        // Check if any animal is eaten by another
        for (int i = 0; i < state.animals.length; i++) {
            for (int j = 0; j < relations.length; j++) {
                if (state.animals[i] == state.boatman && state.animals[relations[j][0] - 1] == state.boatman && relations[j][1] - 1 == i) {
                    return false;
                }
            }
        }
        return true;
    }
    static class State {
        int boatman;
        int[] animals;
        public State() {
            animals = new int[MAX_N];
        }
    }
}

