from collections import deque

MAX_N = 10
MAX_M = 20

def bfs(N, M, relations):
    # Create a queue to store states
    queue = deque()
    current_state = [0] * (N + 1)
    current_state[0] = 0
    queue.append(current_state)
    while queue:
        state = queue.popleft()
        # Check if the current state is the goal state
        if state[0] == 1 and all(state[1:]):
            return True
        # Generate all possible next states
        for i in range(1, N + 1):
            if state[i] == state[0]:
                next_state = state[:]
                next_state[0] = 1 - next_state[0]
                next_state[i] = 1 - next_state[i]
                if is_valid(next_state, relations):
                    queue.append(next_state)
    return False

def is_valid(state, relations):
    # Check if any animal is eaten by another
    for i in range(1, len(state)):
        for j in range(len(relations)):
            if state[i] == state[0] and state[relations[j][0] - 1] == state[0] and relations[j][1] - 1 == i:
                return False
    return True

def main():
    T = int(input())
    for _ in range(T):
        N, M = map(int, input().split())
        relations = [list(map(int, input().split())) for _ in range(M)]
        print("YES" if bfs(N, M, relations) else "NO")

