function bfs(N, M, relations) {
    // Create a queue to store states
    const queue = [];
    const currentState = new Array(N + 1).fill(0);
    currentState[0] = 0;
    queue.push(currentState);
    while (queue.length > 0) {
        const state = queue.shift();
        // Check if the current state is the goal state
        if (state[0] === 1 && state.slice(1).every(x => x === 1)) {
            return true;
        }
        // Generate all possible next states
        for (let i = 1; i <= N; i++) {
            if (state[i] === state[0]) {
                const nextState = state.slice();
                nextState[0] = 1 - nextState[0];
                nextState[i] = 1 - nextState[i];
                if (isValid(nextState, relations)) {
                    queue.push(nextState);
                }
            }
        }
    }
    return false;
}

function isValid(state, relations) {
    // Check if any animal is eaten by another
    for (let i = 1; i < state.length; i++) {
        for (let j = 0; j < relations.length; j++) {
            if (state[i] === state[0] && state[relations[j][0] - 1] === state[0] && relations[j][1] - 1 === i) {
                return false;
            }
        }
    }
    return true;
}

